import React, { useState } from "react";
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Alert,
  CircularProgress,
} from "@mui/material";
import axios from "axios";
import { useNavigate } from "react-router-dom";

const RiderOtpLogin = () => {
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const navigate = useNavigate();

  // Send OTP request (in case rider needs to re-request)
  const sendOtp = async () => {
    try {
      setLoading(true);
      setError("");
      setSuccess("");
      await axios.post("/api/rider/send-otp", { mobile });
      setSuccess("OTP sent successfully. Please check your phone.");
    } catch (err) {
      console.error("❌ OTP request error:", err);
      setError("Failed to send OTP. Try again.");
    } finally {
      setLoading(false);
    }
  };

  // Verify OTP
  const verifyOtp = async () => {
    try {
      setLoading(true);
      setError("");
      setSuccess("");
      const res = await axios.post("/api/rider/verify-otp", { mobile, otp });
      localStorage.setItem("riderToken", res.data.token); // Rider JWT
      setSuccess("OTP verified! Redirecting to dashboard...");
      setTimeout(() => navigate("/rider/dashboard"), 1500);
    } catch (err) {
      console.error("❌ OTP verification error:", err);
      setError("Invalid OTP. Try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      display="flex"
      justifyContent="center"
      alignItems="center"
      minHeight="100vh"
      sx={{ bgcolor: "#f9f9f9" }}
    >
      <Paper sx={{ p: 4, width: 350, textAlign: "center" }}>
        <Typography variant="h5" gutterBottom>
          Rider OTP Login
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <TextField
          label="Mobile Number"
          fullWidth
          margin="normal"
          value={mobile}
          onChange={(e) => setMobile(e.target.value)}
          InputProps={{ startAdornment: <span style={{ marginRight: 8 }}>+91</span> }}
        />

        <TextField
          label="Enter OTP"
          fullWidth
          margin="normal"
          value={otp}
          onChange={(e) => setOtp(e.target.value)}
        />

        {loading ? (
          <CircularProgress sx={{ mt: 2 }} />
        ) : (
          <>
            <Button
              variant="contained"
              fullWidth
              sx={{ mt: 2 }}
              onClick={sendOtp}
              disabled={!mobile}
            >
              Send OTP
            </Button>

            <Button
              variant="contained"
              color="success"
              fullWidth
              sx={{ mt: 2 }}
              onClick={verifyOtp}
              disabled={!mobile || !otp}
            >
              Verify OTP
            </Button>
          </>
        )}
      </Paper>
    </Box>
  );
};

export default RiderOtpLogin;
